    public function render_admin_dashboard() {
        global $wpdb;
        $table_name = $wpdb->prefix . 'ufum_files';

        $per_page = 20;
        $current_page = isset($_GET['paged']) ? max(1, intval($_GET['paged'])) : 1;
        $offset = ($current_page - 1) * $per_page;

        $search = isset($_GET['s']) ? sanitize_text_field($_GET['s']) : '';
        $user_filter = isset($_GET['user_id']) ? intval($_GET['user_id']) : 0;
        $category_filter = isset($_GET['category']) ? sanitize_text_field($_GET['category']) : '';

        $where = '1=1';
        $params = array();

        if (!empty($search)) {
            $where .= ' AND (f.original_name LIKE %s OR f.description LIKE %s)';
            $params[] = '%' . $wpdb->esc_like($search) . '%';
            $params[] = '%' . $wpdb->esc_like($search) . '%';
        }

        if ($user_filter > 0) {
            $where .= ' AND f.user_id = %d';
            $params[] = $user_filter;
        }

        if (!empty($category_filter)) {
            $where .= ' AND f.file_category = %s';
            $params[] = $category_filter;
        }

        $count_query = "SELECT COUNT(*) FROM $table_name f WHERE $where";
        if (!empty($params)) {
            $total_items = $wpdb->get_var($wpdb->prepare($count_query, $params));
        } else {
            $total_items = $wpdb->get_var($count_query);
        }

        $total_pages = ceil($total_items / $per_page);

        $query = "SELECT f.*, u.display_name as user_name, u.user_email 
                  FROM $table_name f 
                  LEFT JOIN {$wpdb->users} u ON f.user_id = u.ID 
                  WHERE $where 
                  ORDER BY f.uploaded_at DESC 
                  LIMIT %d OFFSET %d";

        $params[] = $per_page;
        $params[] = $offset;

        $files = $wpdb->get_results($wpdb->prepare($query, $params));

        ?>
        <div class="wrap">
